ALTER TABLE `sky`.`student_relatives` 
ADD COLUMN `address_id` INT NULL DEFAULT NULL AFTER `phone`,
CHANGE COLUMN `address` `address_line` VARCHAR(100) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_0900_ai_ci' NULL DEFAULT NULL ;

ALTER TABLE `sky`.`student_relatives` 
ADD INDEX `fk_student_relatives_address_id_idx` (`address_id` ASC) VISIBLE;

ALTER TABLE `sky`.`student_relatives` 
ADD CONSTRAINT `fk_student_relatives_address_id`
  FOREIGN KEY (`address_id`)
  REFERENCES `sky`.`address` (`id`)
  ON DELETE RESTRICT
  ON UPDATE NO ACTION;

update addable_titles set name = replace(name, 'область', 'обл.');
update addable_titles set name = replace(name, 'район', 'р-н.');

-- Ырыс а/ө  -> id = 1014  (Джалал-Абадская обл., Сузакский р-н., c.Ырыс)
UPDATE student_relatives
SET address_id = 1014
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%СУЗАК Р-Н.%ЫРЫС А/Ө.%';

-- Барпы а/ө -> id = 982   (c.Барпы)
UPDATE student_relatives
SET address_id = 982
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%СУЗАК Р-Н.%БАРПЫ А/Ө.%';

-- Багыш а/ө -> id = 981  (c.Багыш)
UPDATE student_relatives
SET address_id = 981
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%СУЗАК Р-Н.%БАГЫШ А/Ө.%';

-- Сунак а.  -> id = 1008 (c.Сузак)
UPDATE student_relatives
SET address_id = 1008
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%СУЗАК Р-Н.%СУЗАК А.%';

-- Таш-Булак -> id = 1009 (c.Таш-Булак)
UPDATE student_relatives
SET address_id = 1009
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%СУЗАК Р-Н.%ТАШ-БУЛАК%';

-- Кара-Дарыя (встречается как КАРАДАРЫЯ / КАРА-ДАРИЯ) -> id = 993 (c.Кара-Дарыя)
UPDATE student_relatives
SET address_id = 993
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%СУЗАК Р-Н.%КАРАДАР%'
;

-- Джар-Кыштак (ЖАР-КЫШТАК А.) -> id = 985 (c.Джар-Кыштак)
UPDATE student_relatives
SET address_id = 985
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%СУЗАК Р-Н.%ЖАР-КЫШТАК А.%'
  OR (
    address_id IS NULL
    AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%СУЗАК Р-Н.%КЫШТАК%'
  );

-- Акман а. (Базар-Коргон, Акман а.) -> id = 963 (c.Акман)
UPDATE student_relatives
SET address_id = 963
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%БАЗАР-КОРГОН Ш.%АКМАН А.%'
   OR (
     address_id IS NULL
     AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%БАЗАР-КОГРОН Ш.%АКМАН А.%'
   );

-- Остальной Базар-Коргон (город) -> id = 965 (c.Базар-Коргон)
UPDATE student_relatives
SET address_id = 965
WHERE address_id IS NULL
  AND (
    UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%БАЗАР-КОРГОН Ш.%'
    OR UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%БАЗАР-КОГРОН Ш.%'
  )
  AND UPPER(address_line) NOT LIKE '%АКМАН А.%';

-- Кочкор-Ата (ЖАЛАЛ-АБАД ОБЛ. КОЧКОР-АТА Ш. ...) -> id = 974 (c.Кочкор-Ата)
UPDATE student_relatives
SET address_id = 974
WHERE address_id IS NULL
  AND UPPER(address_line) LIKE 'ЖАЛАЛ-АБАД ОБЛ.%КОЧКОР-АТА Ш.%';


-- Все городские адреса Джалал-Абада (без "ОБЛ.")
-- -> id = 55 (г. Джалал-Абад)
UPDATE student_relatives
SET address_id = 55
WHERE address_id IS NULL
  AND address_line IS NOT NULL
  AND UPPER(address_line) LIKE '%ЖАЛАЛ-АБАД%'
  AND UPPER(address_line) NOT LIKE '%ОБЛ.%';

