update student_relatives set work_place = null where work_place = '';

delete from hr_work_place;

insert into hr_work_place (name) SELECT distinct(work_place) FROM sky.student_relatives where work_place is not null;

UPDATE student_relatives sr
JOIN hr_work_place wp
  ON TRIM(wp.name) = TRIM(sr.work_place)
SET sr.work_place_id = wp.id
WHERE sr.work_place IS NOT NULL;

ALTER TABLE `sky`.`student_relatives` 
DROP COLUMN `work_place`;

ALTER TABLE `sky`.`student_relatives` 
ADD COLUMN `INN` VARCHAR(20) NULL DEFAULT NULL AFTER `work_place_id`;

UPDATE student_relatives
SET
    inn      = TRIM(SUBSTRING_INDEX(passport, '/', -1)),  -- после "/"
    passport = TRIM(SUBSTRING_INDEX(passport, '/',  1))   -- до "/"
WHERE passport LIKE '%/%';

ALTER TABLE `sky`.`student_relatives` 
CHANGE COLUMN `INN` `inn` VARCHAR(20) NULL DEFAULT NULL ;
